import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';
import { useAuth } from '../../context/AuthContext';

export default function AdminDashboard() {
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [pendingCAdmins, setPendingCAdmins] = useState([]);
  const [pendingCommunities, setPendingCommunities] = useState([]);
  const [pendingEvents, setPendingEvents] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [statsRes, pendingUsersRes, pendingComRes] = await Promise.all([
        api.get('/users/stats'),
        api.get('/users/pending-community-admins'),
        api.get('/communities/all?status=pending'),
      ]);
      setStats(statsRes.data.data);
      setPendingCAdmins(pendingUsersRes.data.data || []);
      setPendingCommunities(pendingComRes.data.data || []);
    } catch (err) {
      toast.error('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const approveUser = async (id, name) => {
    try {
      await api.put(`/users/${id}/approve`);
      toast.success(`${name} approved successfully`);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to approve');
    }
  };

  const rejectUser = async (id, name) => {
    const reason = prompt(`Reason for rejecting ${name}:`);
    if (reason === null) return;
    try {
      await api.put(`/users/${id}/reject`, { reason });
      toast.success(`${name} rejected`);
      fetchData();
    } catch (err) {
      toast.error('Failed to reject');
    }
  };

  if (loading) return (
    <div className="loading-screen" style={{ 
      minHeight: '400px',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '16px'
    }}>
      <div className="spinner" style={{ width: '40px', height: '40px', borderWidth: '3px' }} />
      <span style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Loading Dashboard...</span>
    </div>
  );

  return (
    <div style={{ padding: '32px 32px 64px', maxWidth: '1400px', margin: '0 auto' }}>
        {/* Enhanced Header */}
        <div className="page-header" style={{ marginBottom: '32px' }}>
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'flex-start',
            flexWrap: 'wrap',
            gap: '16px'
          }}>
            <div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
                <div style={{ 
                  width: '48px', 
                  height: '48px', 
                  background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                  borderRadius: 'var(--radius-md)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '24px'
                }}>
                  🚀
                </div>
                <div>
                  <h2 style={{ fontFamily: 'var(--font-display)', margin: 0, fontSize: '1.75rem' }}>
                    ADMIN <span className="gradient-text">DASHBOARD</span>
                  </h2>
                  <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: '4px' }}>
                    Welcome back, {user?.name} — System Administration
                  </p>
                </div>
              </div>
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
              <Link to="/admin/users" className="btn btn-outline" style={{ 
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <span>👥</span> Manage Users
              </Link>
              <Link to="/admin/communities" className="btn btn-primary" style={{ 
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <span>🏛️</span> Manage Communities
              </Link>
            </div>
          </div>
        </div>

        {/* Enhanced Stats Grid */}
        {stats && (
          <div className="grid grid-4" style={{ marginBottom: '48px', gap: '20px' }}>
            {[
              { label: 'Total Users', value: stats.total, icon: '👥', color: 'var(--purple-light)', trend: '+12%', bgGradient: 'linear-gradient(135deg, rgba(139, 92, 246, 0.1), rgba(139, 92, 246, 0.05))' },
              { label: 'Pending Approval', value: stats.pending, icon: '⏳', color: 'var(--warning)', trend: `${stats.pending} new`, bgGradient: 'linear-gradient(135deg, rgba(245, 158, 11, 0.1), rgba(245, 158, 11, 0.05))' },
              { label: 'Community Admins', value: stats.communityAdmins, icon: '👑', color: 'var(--pink-accent)', trend: 'Active', bgGradient: 'linear-gradient(135deg, rgba(236, 72, 153, 0.1), rgba(236, 72, 153, 0.05))' },
              { label: 'Students', value: stats.students, icon: '🎓', color: 'var(--cyan-accent)', trend: 'Enrolled', bgGradient: 'linear-gradient(135deg, rgba(6, 182, 212, 0.1), rgba(6, 182, 212, 0.05))' },
            ].map((s, i) => (
              <div key={i} className="stat-card" style={{ 
                background: s.bgGradient,
                border: '1px solid rgba(255,255,255,0.1)',
                transition: 'transform 0.2s, box-shadow 0.2s',
                cursor: 'pointer',
                position: 'relative',
                overflow: 'hidden'
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
                  <span style={{ fontSize: '2rem' }}>{s.icon}</span>
                  <span style={{ 
                    fontSize: '0.75rem', 
                    color: s.color,
                    background: 'rgba(255,255,255,0.1)',
                    padding: '4px 8px',
                    borderRadius: 'var(--radius-sm)'
                  }}>{s.trend}</span>
                </div>
                <div className="stat-value" style={{ color: s.color, fontSize: '2.5rem', fontWeight: 'bold' }}>{s.value}</div>
                <div className="stat-label" style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: '8px' }}>{s.label}</div>
              </div>
            ))}
          </div>
        )}

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '32px' }}>
          {/* Enhanced Pending Community Admin Approvals */}
          <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
              <div>
                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.25rem', margin: 0, display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <span>👥</span> Pending Community Admins
                  {pendingCAdmins.length > 0 && (
                    <span style={{ 
                      background: 'var(--warning)', 
                      color: 'black', 
                      borderRadius: '100px', 
                      padding: '2px 10px', 
                      fontSize: '0.75rem',
                      fontWeight: 'bold'
                    }}>
                      {pendingCAdmins.length} pending
                    </span>
                  )}
                </h3>
                <p style={{ color: 'var(--text-muted)', fontSize: '0.75rem', marginTop: '4px' }}>
                  Review and approve community admin applications
                </p>
              </div>
              <Link to="/admin/users?role=community_admin&status=pending" style={{ 
                fontSize: '0.8rem', 
                color: 'var(--purple-light)',
                textDecoration: 'none',
                fontWeight: '500'
              }}>View All →</Link>
            </div>

            {pendingCAdmins.length === 0 ? (
              <div className="card" style={{ textAlign: 'center', padding: '48px 24px' }}>
                <div style={{ fontSize: '3rem', marginBottom: '16px' }}>✅</div>
                <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>No pending approvals</div>
                <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '8px' }}>All community admin requests have been processed</div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {pendingCAdmins.slice(0, 5).map(u => (
                  <div key={u._id} className="card" style={{ padding: '20px', transition: 'transform 0.2s' }}>
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: '12px', marginBottom: '16px' }}>
                      <div className="avatar" style={{ 
                        width: '48px', 
                        height: '48px', 
                        background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '1.2rem',
                        fontWeight: 'bold'
                      }}>{u.name?.charAt(0)}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 600, fontSize: '1rem', marginBottom: '4px' }}>{u.name}</div>
                        <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{u.email}</div>
                      </div>
                      <span className="badge badge-pending" style={{ background: 'var(--warning)', color: 'black' }}>Pending Review</span>
                    </div>

                    {u.communityName && (
                      <div style={{ 
                        marginBottom: '16px', 
                        padding: '12px', 
                        background: 'var(--bg-elevated)', 
                        borderRadius: 'var(--radius-sm)',
                        borderLeft: `3px solid var(--purple-light)`
                      }}>
                        <div style={{ display: 'flex', gap: '16px', flexWrap: 'wrap', marginBottom: '8px' }}>
                          <div><strong style={{ color: 'var(--purple-light)' }}>🏛️ Community:</strong> {u.communityName}</div>
                          <div><strong style={{ color: 'var(--purple-light)' }}>📂 Category:</strong> {u.communityCategory}</div>
                        </div>
                        <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                          {u.communityDescription?.substring(0, 100)}...
                        </div>
                      </div>
                    )}

                    <div style={{ display: 'flex', gap: '12px' }}>
                      <button 
                        onClick={() => approveUser(u._id, u.name)} 
                        className="btn btn-success btn-sm" 
                        style={{ 
                          flex: 1, 
                          justifyContent: 'center',
                          background: 'linear-gradient(135deg, #10b981, #059669)',
                          border: 'none'
                        }}
                      >
                        ✓ Approve
                      </button>
                      <button 
                        onClick={() => rejectUser(u._id, u.name)} 
                        className="btn btn-danger btn-sm" 
                        style={{ 
                          flex: 1, 
                          justifyContent: 'center',
                          background: 'linear-gradient(135deg, #ef4444, #dc2626)',
                          border: 'none'
                        }}
                      >
                        ✗ Reject
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Enhanced Pending Community Approvals */}
          <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
              <div>
                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.25rem', margin: 0, display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <span>🏛️</span> Pending Communities
                  {pendingCommunities.length > 0 && (
                    <span style={{ 
                      background: 'var(--warning)', 
                      color: 'black', 
                      borderRadius: '100px', 
                      padding: '2px 10px', 
                      fontSize: '0.75rem',
                      fontWeight: 'bold'
                    }}>
                      {pendingCommunities.length} pending
                    </span>
                  )}
                </h3>
                <p style={{ color: 'var(--text-muted)', fontSize: '0.75rem', marginTop: '4px' }}>
                  Review new community submissions
                </p>
              </div>
              <Link to="/admin/communities" style={{ 
                fontSize: '0.8rem', 
                color: 'var(--purple-light)',
                textDecoration: 'none',
                fontWeight: '500'
              }}>View All →</Link>
            </div>

            {pendingCommunities.length === 0 ? (
              <div className="card" style={{ textAlign: 'center', padding: '48px 24px' }}>
                <div style={{ fontSize: '3rem', marginBottom: '16px' }}>✅</div>
                <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>No pending communities</div>
                <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '8px' }}>All community submissions have been reviewed</div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {pendingCommunities.slice(0, 5).map(c => (
                  <div key={c._id} className="card" style={{ padding: '20px', transition: 'transform 0.2s' }}>
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: '12px', marginBottom: '16px' }}>
                      <div className="avatar" style={{ 
                        borderRadius: 'var(--radius-sm)', 
                        background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))',
                        width: '48px',
                        height: '48px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '1.2rem',
                        fontWeight: 'bold'
                      }}>{c.name?.charAt(0)}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 600, fontSize: '1rem', marginBottom: '4px' }}>{c.name}</div>
                        <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>by {c.admin?.name}</div>
                      </div>
                      <span className={`badge badge-${c.category?.toLowerCase()}`} style={{ 
                        background: c.category === 'academic' ? 'var(--purple-light)' : 
                                   c.category === 'cultural' ? 'var(--pink-accent)' : 'var(--cyan-accent)',
                        color: 'white'
                      }}>{c.category}</span>
                    </div>

                    <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '16px', lineHeight: '1.5' }}>
                      {c.description?.substring(0, 120)}...
                    </p>

                    <div style={{ display: 'flex', gap: '12px' }}>
                      <button 
                        onClick={async () => {
                          try { 
                            await api.put(`/communities/${c._id}/approve`); 
                            toast.success('Community approved!'); 
                            fetchData(); 
                          } catch (e) { 
                            toast.error('Failed to approve'); 
                          }
                        }} 
                        className="btn btn-success btn-sm" 
                        style={{ 
                          flex: 1, 
                          justifyContent: 'center',
                          background: 'linear-gradient(135deg, #10b981, #059669)',
                          border: 'none'
                        }}
                      >
                        ✓ Approve
                      </button>
                      <button 
                        className="btn btn-danger btn-sm" 
                        style={{ 
                          flex: 1, 
                          justifyContent: 'center',
                          background: 'linear-gradient(135deg, #ef4444, #dc2626)',
                          border: 'none'
                        }} 
                        onClick={async () => {
                          const reason = prompt('Rejection reason:');
                          if (!reason) return;
                          try { 
                            await api.put(`/communities/${c._id}/reject`, { reason }); 
                            toast.success('Community rejected'); 
                            fetchData(); 
                          } catch (e) { 
                            toast.error('Failed'); 
                          }
                        }}
                      >
                        ✗ Reject
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Enhanced Quick Links */}
        <div style={{ marginTop: '48px' }}>
          <div style={{ marginBottom: '24px' }}>
            <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.25rem', margin: 0, display: 'flex', alignItems: 'center', gap: '12px' }}>
              <span>⚡</span> QUICK ACTIONS
            </h3>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '4px' }}>
              Frequently used administrative tools
            </p>
          </div>

          <div className="grid grid-4" style={{ gap: '20px' }}>
            {[
              { to: '/admin/users', label: 'All Users', icon: '👥', desc: `${stats?.total || 0} total members`, color: 'var(--purple-light)' },
              { to: '/admin/users?status=pending', label: 'Pending Users', icon: '⏳', desc: `${stats?.pending || 0} waiting for approval`, color: 'var(--warning)' },
              { to: '/admin/communities', label: 'Communities', icon: '🏛️', desc: 'Manage all communities', color: 'var(--cyan-accent)' },
              { to: '/clubs', label: 'Public View', icon: '🌐', desc: 'See portal as visitor', color: 'var(--pink-accent)' },
            ].map((item, i) => (
              <Link key={i} to={item.to} style={{ textDecoration: 'none' }}>
                <div className="card" style={{ 
                  cursor: 'pointer', 
                  textAlign: 'center', 
                  padding: '24px 16px',
                  transition: 'transform 0.2s, box-shadow 0.2s',
                  borderTop: `3px solid ${item.color}`,
                  position: 'relative',
                  overflow: 'hidden'
                }}>
                  <div style={{ 
                    fontSize: '2.5rem', 
                    marginBottom: '12px',
                    transition: 'transform 0.2s'
                  }}>{item.icon}</div>
                  <div style={{ fontWeight: 700, fontSize: '0.9rem', marginBottom: '4px', color: 'var(--text-primary)' }}>{item.label}</div>
                  <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{item.desc}</div>
                </div>
              </Link>
            ))}
          </div>
        </div>
    </div>
  );
}
